#include<bits/stdc++.h>
using namespace std;
int rt[600010],cnt[18600010],son[18600010][2];
int s[600010],tot,n,m;
void insert(int a,int b,int t,int x)
{
    if(t<0)
    {
        return;
    }
    int i=(x>>t)&1;
    son[a][!i]=son[b][!i];
    son[a][i]=++tot;
    cnt[son[a][i]]=cnt[son[b][i]]+1;
    insert(son[a][i],son[b][i],t-1,x);
}
int query(int a,int b,int t,int x)
{
    if(t<0)
    {
        return 0;
    }
    int i=(x>>t)&1;
    if(cnt[son[b][!i]]>cnt[son[a][!i]])
    {
        return (1<<t)+query(son[a][!i],son[b][!i],t-1,x);
    }
    return query(son[a][i],son[b][i],t-1,x);
}
int main()
{
    scanf("%d%d",&n,&m);
    rt[0]=++tot;
    insert(rt[0],0,25,0);
    for(int i=1;i<=n;i++)
    {
        int x;
        scanf("%d",&x);
        s[i]=s[i-1]^x;
        rt[i]=++tot;
        insert(rt[i],rt[i-1],25,s[i]);
    }
    while(m--)
    {
        char ch;
        cin>>ch;
        if(ch=='A')
        {
            int x;
            scanf("%d",&x);
            n++;
            s[n]=s[n-1]^x;
            rt[n]=++tot;
            insert(rt[n],rt[n-1],25,s[n]);
        }
        else
        {
            int l,r,x;
            scanf("%d%d%d",&l,&r,&x);
            l--,r--;
            if(l==0)
            {
                printf("%d\n",query(0,rt[r],25,x^s[n]));
            }
            else
            {
                printf("%d\n",query(rt[l-1],rt[r],25,x^s[n]));
            }
        }
    }
    return 0;
}
